:root {
  --color-accent: rgb(230, 170, 40);
}

* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  background: #000;
}

img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

a,
p {
  color: var(--color-accent);
  text-decoration: none;
  font-family: "Basis Grotesque Pro";
  text-transform: uppercase;
  font-size: 12px;
}

nav {
  position: fixed;
  top: 0;
  width: 100%;
  padding: 1.5em 2em;
  display: flex;
  align-items: center;
}

footer {
  position: fixed;
  bottom: 0;
  width: 100%;
  padding: 1.5em 2em;
  display: flex;
  justify-content: space-between;
  align-items: center;
}

nav > div {
  flex: 1;
}

.links-1 {
  display: flex;
  gap: 2em;
}

.links-2 {
  display: flex;
  gap: 2em;
  justify-content: flex-end;
}

.logo {
  display: flex;
  justify-content: center;
}

.logo a {
  font-family: "PP Monument Extended";
  font-size: 16px;
  font-weight: bolder;
  letter-spacing: -0.02em;
}

.container {
  width: 100%;
  height: 2000vh;
}

.active-slide {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  overflow: hidden;
  background: #000;
  opacity: 0.35;
  z-index: -1;
}

.active-slide img {
  position: absolute;
  filter: blur(50px);
  transform: scale(1.125);
}

.slider {
  position: fixed;
  top: 0;
  width: 100vw;
  height: 100vh;
  transform-style: preserve-3d;
  perspective: 750px;
  overflow: hidden;
}

.slide {
  position: absolute;
  width: 400px;
  height: 500px;
  overflow: hidden;
}

.slide-copy p {
  text-transform: uppercase;
  text-align: center;
  font-family: "PP Monument Extended";
  font-size: 13px;
  font-weight: bolder;
  line-height: 150%;
  color: var(--color-accent);
}

